mapper.select:
select c.name clazzName, count(*) num
from student s left join clazz c on s.clazz_id = c.id group by c.name
order by num asc;

mapper.update:
update student
name = #{name}, no = #{no}, phone = #{phone}, gender = #{gender}, degree = #{degree}, id_card = #{idCard}, is_college = #{isCollege}, address = #{address}, graduation_date = #{graduationDate}, clazz_id = #{clazzId}, update_time = #{updateTime},
where id = #{id}

